class PaymentValidator {
    
    fun validateCard(card: PaymentCard): ValidationResult {
        val errors = mutableListOf<String>()
        
        if (!isValidCardNumber(card.cardNumber)) {
            errors.add("Invalid card number")
        }
        
        if (!isValidExpiry(card.expiryMonth, card.expiryYear)) {
            errors.add("Invalid expiry date")
        }
        
        if (!isValidCVV(card.cvv)) {
            errors.add("Invalid CVV")
        }
        
        if (card.cardHolderName.isBlank()) {
            errors.add("Card holder name is required")
        }
        
        return if (errors.isEmpty()) {
            ValidationResult(true, null)
        } else {
            ValidationResult(false, errors.joinToString(", "))
        }
    }
    
    private fun isValidCardNumber(cardNumber: String): Boolean {
        val cleaned = cardNumber.replace("\\s".toRegex(), "")
        if (cleaned.length !in 13..19) return false
        if (!cleaned.all { it.isDigit() }) return false
        
        return luhnCheck(cleaned)
    }
    
    private fun luhnCheck(cardNumber: String): Boolean {
        var sum = 0
        var alternate = false
        
        for (i in cardNumber.length - 1 downTo 0) {
            var digit = cardNumber[i].toString().toInt()
            
            if (alternate) {
                digit *= 2
                if (digit > 9) {
                    digit -= 9
                }
            }
            
            sum += digit
            alternate = !alternate
        }
        
        return sum % 10 == 0
    }
    
    private fun isValidExpiry(month: Int, year: Int): Boolean {
        if (month !in 1..12) return false
        
        val currentYear = java.util.Calendar.getInstance().get(java.util.Calendar.YEAR)
        val currentMonth = java.util.Calendar.getInstance().get(java.util.Calendar.MONTH) + 1
        
        if (year < currentYear) return false
        if (year == currentYear && month < currentMonth) return false
        
        return true
    }
    
    private fun isValidCVV(cvv: String): Boolean {
        return cvv.length in 3..4 && cvv.all { it.isDigit() }
    }
    
    fun validateAmount(amount: Double): Boolean {
        return amount > 0 && amount <= 999999.99
    }
}

data class ValidationResult(
    val isValid: Boolean,
    val errorMessage: String?
)

class PaymentProcessor(private val context: Context) {
    
    private val storage = PaymentStorage(context)
    private val validator = PaymentValidator()
    private val securityManager = PaymentSecurityManager(context)
    
    suspend fun processInAppPurchase(purchase: InAppPurchase): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                if (!validator.validateAmount(purchase.price)) {
                    return@withContext PaymentResult(false, "Invalid amount", null)
                }
                
                val transactionId = generateTransactionId()
                
                val transaction = WalletTransaction(
                    transactionId = transactionId,
                    amount = purchase.price,
                    currency = purchase.currency,
                    timestamp = System.currentTimeMillis(),
                    status = TransactionStatus.COMPLETED
                )
                
                storage.saveTransaction(transaction)
                
                PaymentResult(true, "Purchase successful", transactionId)
            } catch (e: Exception) {
                Log.e("PaymentProcessor", "Purchase failed", e)
                PaymentResult(false, "Purchase failed: ${e.message}", null)
            }
        }
    }
    
    suspend fun processCardPayment(card: PaymentCard, amount: Double, currency: String): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                val validationResult = validator.validateCard(card)
                if (!validationResult.isValid) {
                    return@withContext PaymentResult(false, validationResult.errorMessage ?: "Invalid card", null)
                }
                
                if (!validator.validateAmount(amount)) {
                    return@withContext PaymentResult(false, "Invalid amount", null)
                }
                
                storage.saveCard(card)
                
                val transactionId = generateTransactionId()
                
                val transaction = WalletTransaction(
                    transactionId = transactionId,
                    amount = amount,
                    currency = currency,
                    timestamp = System.currentTimeMillis(),
                    status = TransactionStatus.COMPLETED
                )
                
                storage.saveTransaction(transaction)
                
                PaymentResult(true, "Payment successful", transactionId)
            } catch (e: Exception) {
                Log.e("PaymentProcessor", "Payment failed", e)
                PaymentResult(false, "Payment failed: ${e.message}", null)
            }
        }
    }
    
    suspend fun processWalletTransaction(amount: Double, currency: String, userId: String): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                if (!validator.validateAmount(amount)) {
                    return@withContext PaymentResult(false, "Invalid amount", null)
                }
                
                val transactionId = generateTransactionId()
                
                val transaction = WalletTransaction(
                    transactionId = transactionId,
                    amount = amount,
                    currency = currency,
                    timestamp = System.currentTimeMillis(),
                    status = TransactionStatus.COMPLETED
                )
                
                storage.saveTransaction(transaction)
                
                PaymentResult(true, "Transaction successful", transactionId)
            } catch (e: Exception) {
                Log.e("PaymentProcessor", "Transaction failed", e)
                PaymentResult(false, "Transaction failed: ${e.message}", null)
            }
        }
    }
    
    suspend fun getTransactionHistory(): List<WalletTransaction> {
        return storage.getDecryptedTransactions()
    }
    
    suspend fun getSavedCards(): List<PaymentCard> {
        return storage.getDecryptedCards()
    }
    
    suspend fun refundTransaction(transactionId: String): PaymentResult {
        return withContext(Dispatchers.IO) {
            try {
                val transactions = storage.getDecryptedTransactions()
                val transaction = transactions.find { it.transactionId == transactionId }
                    ?: return@withContext PaymentResult(false, "Transaction not found", null)
                
                val refundedTransaction = transaction.copy(status = TransactionStatus.REFUNDED)
                storage.saveTransaction(refundedTransaction)
                
                PaymentResult(true, "Refund successful", transactionId)
            } catch (e: Exception) {
                Log.e("PaymentProcessor", "Refund failed", e)
                PaymentResult(false, "Refund failed: ${e.message}", null)
            }
        }
    }
    
    private fun generateTransactionId(): String {
        return "TXN_${System.currentTimeMillis()}_${(1000..9999).random()}"
    }
}

data class PaymentResult(
    val success: Boolean,
    val message: String,
    val transactionId: String?
)

class PaymentModule(context: Context) {
    
    private val processor = PaymentProcessor(context)
    private val storage = PaymentStorage(context)
    
    suspend fun addCard(card: PaymentCard): ValidationResult {
        val validator = PaymentValidator()
        val validationResult = validator.validateCard(card)
        
        if (validationResult.isValid) {
            storage.saveCard(card)
        }
        
        return validationResult
    }
    
    suspend fun purchaseProduct(purchase: InAppPurchase): PaymentResult {
        return processor.processInAppPurchase(purchase)
    }
    
    suspend fun payWithCard(card: PaymentCard, amount: Double, currency: String): PaymentResult {
        return processor.processCardPayment(card, amount, currency)
    }
    
    suspend fun walletTransfer(amount: Double, currency: String, userId: String): PaymentResult {
        return processor.processWalletTransaction(amount, currency, userId)
    }
    
    suspend fun getTransactions(): List<WalletTransaction> {
        return processor.getTransactionHistory()
    }
    
    suspend fun getCards(): List<PaymentCard> {
        return processor.getSavedCards()
    }
    
    suspend fun refund(transactionId: String): PaymentResult {
        return processor.refundTransaction(transactionId)
    }
    
    suspend fun clearPaymentData(): Boolean {
        return storage.clearAllData()
    }
}